mapper.select:
SELECT id, sku_id, level_name, level_seq, unit_code, length, width, height, net_weight, gross_weight, is_base_unit, is_sellable, status, deleted, created_at, updated_at, created_by, updated_by FROM packaging_level WHERE deleted = 0
AND sku_id = #{skuId}
AND status = #{status}
ORDER BY sku_id ASC, level_seq ASC, id ASC
